import 'dart:convert';

Package packageFromJson(String str) => Package.fromJson(json.decode(str));

String packageToJson(Package data) => json.encode(data.toJson());

class Package {
    String name;
    String author;
    String version;
    String description;
    Repository repository;
    String license;
    String type;
    Exports exports;
    List<String> keywords;
    Engines engines;
    Scripts scripts;
    DevDependencies devDependencies;
    List<String> files;

    Package({
        required this.name,
        required this.author,
        required this.version,
        required this.description,
        required this.repository,
        required this.license,
        required this.type,
        required this.exports,
        required this.keywords,
        required this.engines,
        required this.scripts,
        required this.devDependencies,
        required this.files,
    });

    factory Package.fromJson(Map<String, dynamic> json) => Package(
        name: json["name"],
        author: json["author"],
        version: json["version"],
        description: json["description"],
        repository: Repository.fromJson(json["repository"]),
        license: json["license"],
        type: json["type"],
        exports: Exports.fromJson(json["exports"]),
        keywords: List<String>.from(json["keywords"].map((x) => x)),
        engines: Engines.fromJson(json["engines"]),
        scripts: Scripts.fromJson(json["scripts"]),
        devDependencies: DevDependencies.fromJson(json["devDependencies"]),
        files: List<String>.from(json["files"].map((x) => x)),
    );

    Map<String, dynamic> toJson() => {
        "name": name,
        "author": author,
        "version": version,
        "description": description,
        "repository": repository.toJson(),
        "license": license,
        "type": type,
        "exports": exports.toJson(),
        "keywords": List<dynamic>.from(keywords.map((x) => x)),
        "engines": engines.toJson(),
        "scripts": scripts.toJson(),
        "devDependencies": devDependencies.toJson(),
        "files": List<dynamic>.from(files.map((x) => x)),
    };
}

class DevDependencies {
    DevDependencies();

    factory DevDependencies.fromJson(Map<String, dynamic> json) => DevDependencies(
    );

    Map<String, dynamic> toJson() => {
    };
}

class Engines {
    String node;

    Engines({
        required this.node,
    });

    factory Engines.fromJson(Map<String, dynamic> json) => Engines(
        node: json["node"],
    );

    Map<String, dynamic> toJson() => {
        "node": node,
    };
}

class Exports {
    String exportsImport;
    String require;

    Exports({
        required this.exportsImport,
        required this.require,
    });

    factory Exports.fromJson(Map<String, dynamic> json) => Exports(
        exportsImport: json["import"],
        require: json["require"],
    );

    Map<String, dynamic> toJson() => {
        "import": exportsImport,
        "require": require,
    };
}

class Repository {
    String type;
    String url;

    Repository({
        required this.type,
        required this.url,
    });

    factory Repository.fromJson(Map<String, dynamic> json) => Repository(
        type: json["type"],
        url: json["url"],
    );

    Map<String, dynamic> toJson() => {
        "type": type,
        "url": url,
    };
}

class Scripts {
    String test;
    String testCi;
    String docs;
    String dist;

    Scripts({
        required this.test,
        required this.testCi,
        required this.docs,
        required this.dist,
    });

    factory Scripts.fromJson(Map<String, dynamic> json) => Scripts(
        test: json["test"],
        testCi: json["test:ci"],
        docs: json["docs"],
        dist: json["dist"],
    );

    Map<String, dynamic> toJson() => {
        "test": test,
        "test:ci": testCi,
        "docs": docs,
        "dist": dist,
    };
}
